 98→    public StreamTask assignNextTask(final TaskExecutor executor) {
 99→        return returnWithTasksLocked(() -> {
100→            if (!taskExecutors.contains(executor)) {
101→                throw new IllegalArgumentException("The requested executor for getting next task to assign is unrecognized");
102→            }
103→
104→            // the most naive scheduling algorithm for now: give the next unlocked, unassigned, and  processable task
105→            for (final StreamTask task : tasks.activeInitializedTasks()) {
106→                if (!assignedTasks.containsKey(task.id()) &&
107→                    !lockedTasks.contains(task.id()) &&
108→                    canProgress(task, time.milliseconds()) &&
109→                    !hasUncaughtException(task.id())
110→                ) {
111→
112→                    assignedTasks.put(task.id(), executor);
113→
114→                    log.debug("Assigned task {} to executor {}", task.id(), executor.name());
115→
116→                    return task;
117→                }
118→            }
119→
120→            log.debug("Found no assignable task for executor {}", executor.name());
121→
122→            return null;
123→        });
124→    }
125→
126→    @Override
127→    public void awaitProcessableTasks(final Supplier<Boolean> isShuttingDown) throws InterruptedException {
128→        final boolean interrupted = returnWithTasksLocked(() -> {
129→            for (final StreamTask task : tasks.activeInitializedTasks()) {
130→                if (!assignedTasks.containsKey(task.id()) &&
131→                    !lockedTasks.contains(task.id()) &&
132→                    canProgress(task, time.milliseconds()) &&
133→                    !hasUncaughtException(task.id())
134→                ) {
135→                    log.debug("Await unblocked: returning early from await since a processable task {} was found", task.id());
136→                    return false;
137→                }
138→            }
139→            try {
140→                // We re-check the shutdownRequest atomic boolean to avoid a race condition. If this thread was
141→                // previously interrupted while awaiting tasksCondition, it is possible to miss the signalAll that
142→                // is called during shutdown. If this happens, we end up blocking in the await forever.
143→                if (!isShuttingDown.get()) {
144→                    log.debug("Await blocking");
145→                    tasksCondition.await();
146→                } else {
147→                    log.debug("Not awaiting since shutdown was requested");
148→                }
149→            } catch (final InterruptedException ignored) {
150→                // we interrupt the thread for shut down and pause.
151→                // we can ignore this exception.
152→                log.debug("Await unblocked: Interrupted while waiting for processable tasks");
153→                return true;
154→            }
155→            log.debug("Await unblocked: Woken up to check for processable tasks");
156→            return false;
157→        });
158→
159→        if (interrupted) {
160→            throw new InterruptedException();
161→        }
162→    }
