884→
885→            // first set the running flag and then
886→            // notify the condition in case the thread is waiting on it;
887→            // note this ordering should not be changed
888→            stateUpdaterThread.isRunning.set(false);
889→
890→            tasksAndActionsLock.lock();
891→            try {
