2005→    protected Map<String, Map<Integer, LagInfo>> allLocalStorePartitionLags(final List<Task> tasksToCollectLagFor) {
2006→        final Map<String, Map<Integer, LagInfo>> localStorePartitionLags = new TreeMap<>();
2007→        final Collection<TopicPartition> allPartitions = new LinkedList<>();
2008→        final Map<TopicPartition, Long> allChangelogPositions = new HashMap<>();
2009→
2010→        // Obtain the current positions, of all the active-restoring and standby tasks
2011→        for (final Task task : tasksToCollectLagFor) {
2012→            allPartitions.addAll(task.changelogPartitions());
2013→            // Note that not all changelog partitions, will have positions; since some may not have started
2014→            allChangelogPositions.putAll(task.changelogOffsets());
2015→        }
2016→
2017→        log.debug("Current changelog positions: {}", allChangelogPositions);
2018→        final Map<TopicPartition, ListOffsetsResultInfo> allEndOffsets;
2019→        allEndOffsets = fetchEndOffsets(allPartitions, adminClient);
2020→        log.debug("Current end offsets :{}", allEndOffsets);
2021→
2022→        for (final Map.Entry<TopicPartition, ListOffsetsResultInfo> entry : allEndOffsets.entrySet()) {
2023→            // Avoiding an extra admin API lookup by computing lags for not-yet-started restorations
2024→            // from zero instead of the real "earliest offset" for the changelog.
2025→            // This will yield the correct relative order of lagginess for the tasks in the cluster,
2026→            // but it is an over-estimate of how much work remains to restore the task from scratch.
2027→            final long earliestOffset = 0L;
2028→            final long changelogPosition = allChangelogPositions.getOrDefault(entry.getKey(), earliestOffset);
2029→            final long latestOffset = entry.getValue().offset();
2030→            final LagInfo lagInfo = new LagInfo(changelogPosition == Task.LATEST_OFFSET ? latestOffset : changelogPosition, latestOffset);
2031→            final String storeName = streamsMetadataState.storeForChangelogTopic(entry.getKey().topic());
2032→            localStorePartitionLags.computeIfAbsent(storeName, ignored -> new TreeMap<>())
2033→                .put(entry.getKey().partition(), lagInfo);
2034→        }
2035→
2036→        return Collections.unmodifiableMap(localStorePartitionLags);
2037→    }
